      labSheet: { experimentName: 'Determination of Coefficient of Discharge of Venturimeter', aim: 'To determine Cd of a venturimeter installed in a pipe line.', apparatus: ['venturimeter test rig', 'differential manometer', 'measuring tank', 'stopwatch'], theory: 'Actual discharge divided by theoretical discharge gives coefficient of discharge.', procedure: ['Start pump and remove air.', 'Set steady flow.', 'Record manometer difference.', 'Collect water in measuring tank for known time.', 'Calculate actual discharge.', 'Calculate theoretical discharge and Cd.'], observationTable: { headers: ['Trial', 'Manometer head', 'Volume', 'Time', 'Q actual', 'Cd'], rows: 5 }, precautions: ['Remove air bubbles.', 'Keep flow steady.', 'Read both limbs at eye level.', 'Measure collection time accurately.'], result: 'Coefficient of discharge of the venturimeter is obtained from actual and theoretical discharge.' },
