      staticDiagrams: [{ file: 'pelton-wheel.svg', caption: 'Pelton wheel runner, nozzle and bucket action.', labels: ['Nozzle', 'Jet', 'Bucket', 'Runner'] }, { file: 'turbine-impulse-reaction.svg', caption: 'Impulse and reaction turbine comparison.', labels: ['Impulse', 'Reaction', 'Runner', 'Draft tube'] }],
      comparisonTable: { title: 'Hydraulic Turbine Selection', headers: ['Turbine', 'Head', 'Discharge', 'Specific speed', 'Feature'], rows: [['Pelton', 'high', 'low', 'low', 'impulse jet'], ['Francis', 'medium', 'medium', 'medium', 'mixed flow reaction'], ['Kaplan', 'low', 'high', 'high', 'axial flow reaction'], ['Propeller', 'low', 'high', 'high', 'fixed blades']] },
