      labSheet: { experimentName: 'Performance Test on Pelton Wheel', aim: 'To determine efficiency of a Pelton turbine at different loads.', apparatus: ['Pelton turbine test rig', 'pressure gauge', 'flow meter', 'tachometer', 'brake dynamometer'], theory: 'Water power is rho g Q H and shaft power is measured by brake load and speed.', procedure: ['Start pump and set nozzle opening.', 'Record head and discharge.', 'Apply brake load.', 'Measure speed.', 'Calculate water power and shaft power.', 'Plot efficiency versus load.'], observationTable: { headers: ['Load', 'Head', 'Discharge', 'Speed', 'Shaft power', 'Efficiency'], rows: 6 }, precautions: ['Avoid sudden load changes.', 'Keep water supply steady.', 'Read gauges without parallax.', 'Do not touch rotating runner.'], result: 'Turbine efficiency varies with load and reaches a maximum near design condition.' },
