      staticDiagrams: [{ file: 'centrifugal-pump.svg', caption: 'Centrifugal pump components and flow path.', labels: ['Impeller eye', 'Impeller', 'Volute casing', 'Delivery pipe'] }, { file: 'bernoulli-pipe.svg', caption: 'Pump head is added to pipe energy equation.', labels: ['Suction', 'Delivery', 'Head'] }],
      comparisonTable: { title: 'Centrifugal and Reciprocating Pumps', headers: ['Feature', 'Centrifugal pump', 'Reciprocating pump'], rows: [['Type', 'rotodynamic', 'positive displacement'], ['Discharge', 'large and smooth', 'small and pulsating'], ['Head', 'low to medium/high by stages', 'high'], ['Priming', 'needed', 'less critical'], ['Air vessel', 'not usual', 'used to smooth flow']] },
