      labSheet: { experimentName: 'Performance Test on Centrifugal Pump', aim: 'To determine pump efficiency at different discharge values.', apparatus: ['centrifugal pump test rig', 'flow meter', 'pressure gauges', 'wattmeter', 'tachometer'], theory: 'Pump efficiency is useful water power divided by input power.', procedure: ['Prime the pump.', 'Start motor and set valve opening.', 'Record suction and delivery pressure.', 'Measure discharge.', 'Record input power.', 'Calculate head, water power and efficiency.'], observationTable: { headers: ['Trial', 'Q', 'Head', 'Input power', 'Water power', 'Efficiency'], rows: 6 }, precautions: ['Prime before starting.', 'Do not run dry.', 'Avoid throttling fully closed for long time.', 'Check gauge zero.'], result: 'Centrifugal pump efficiency varies with discharge and reaches maximum near rated point.' },
